  ('diplomatic-9e854390-moex-00066', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '今年（2025年）3月賴清德總統提到，臺灣當前面對了五大國安及統戰威脅，他並提出十七項因應策 略。請問下列何者並非賴總統提到的五大威脅？', '["中國對國家主權的威脅", "中國對國軍的滲透及間諜活動的威脅", "中國藉「融合發展」吸引臺商與臺青的威脅", "中國對於臺灣民主體制的威脅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00067', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '2024年6月21日，中共國台辦與其他部門共同公布一份文件名為《關於依法懲治「台獨」頑固分子 分裂國家、煽動分裂國家犯罪的意見》，共22條。依照此一文件，下列何者屬於對於「台獨」的定義 範圍？', '["主張「和平統一」", "主張「中國人不打中國人」", "主張「兩岸一家親」", "「推動臺灣加入僅限主權國家參加的國際組織」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00068', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '行政院大陸委員會於 2025年4月16日頒布的《陸法字第1140400361號解釋令》，持有中國大陸下 列那一個證件，將喪失臺灣人民身分，並會被註銷臺灣身分？', '["臺胞證", "居住證", "旅行證", "定居證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00069', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '美國對臺灣的安全承諾上，有所謂的「戰略模糊（Strategicambiguity）」政策，下列何者不是此一政策 的內涵？', '["不明白宣示是否將協助臺灣維持足夠的自我防衛能力", "1979年美國的「臺灣關係法」：「任何企圖以非和平方式來決定臺灣的前途之舉……將為美國所嚴 重關切」，「嚴重關切」是一個模糊的概念", "承諾協防臺灣可能導致臺灣反攻大陸或者進一步宣布獨立，而拒絕協防臺灣可能導致中國直接動武", "「戰略模糊」的目的：藉由「雙重嚇阻」來「維持現狀」，一方面嚇阻中國使用武力，一方面嚇阻臺 灣宣布獨立"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00070', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '2016年5月民進黨重新上台執政以來，兩岸之間的事務性談判（海基會和海協會）終止至今，有關兩 岸雙方的立場，下列何者錯誤？', '["北京要求：民進黨必須先廢除「台獨黨綱」，才有可能和北京談判", "民進黨政府並不反對兩岸談判，但必須在對等、尊嚴的原則下", "民進黨政府視「中國為境外敵對勢力」，反對兩岸談判", "北京要求：兩岸協商須在「九二共識」的基礎上，才能得到恢復"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
